import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import api from './api/axiosConfig';
import mockProducts from './data/mockProducts.json';

const Home = () => {
  const [products, setProducts] = useState(mockProducts);
  const [selectedCategory, setSelectedCategory] = useState("All Categories");

  useEffect(() => {
    // Attempt to load live products, combine with mock or fall back cleanly
    api.get('/products')
      .then(res => {
          if(res.data && res.data.length > 0) {
              setProducts([...res.data, ...mockProducts.filter(mp => !res.data.find(rp => rp.name === mp.name))]);
          }
      })
      .catch(err => {
          console.log("Backend not active. Relying purely on presentation fallback data.");
      });
  }, []);

  const categories = ["All Categories", ...new Set(products.map(p => p.categoryName || 'General'))].sort();

  const filteredProducts = selectedCategory === "All Categories" 
    ? products 
    : products.filter(p => (p.categoryName || 'General') === selectedCategory);

  return (
    <div className="py-8 px-4 sm:px-6 lg:px-8 max-w-screen-2xl mx-auto flex flex-col md:flex-row gap-8">
      {/* Sidebar Navigation */}
      <aside className="w-full md:w-64 flex-shrink-0 bg-white rounded-2xl shadow-sm border border-gray-100 p-6 h-fit">
        <h2 className="text-2xl font-extrabold text-gray-900 mb-6 border-b pb-4">Categories</h2>
        <ul className="space-y-2">
          {categories.map(cat => (
            <li key={cat}>
              <button 
                onClick={() => setSelectedCategory(cat)}
                className={`w-full text-left px-4 py-3 rounded-lg font-medium transition-all duration-200 ${selectedCategory === cat ? 'bg-primary text-white shadow-md' : 'text-gray-600 hover:bg-indigo-50 hover:text-primary'}`}
              >
                {cat}
                <span className="float-right bg-white/20 px-2 py-0.5 rounded-full text-xs">
                  {cat === "All Categories" ? products.length : products.filter(p => (p.categoryName || 'General') === cat).length}
                </span>
              </button>
            </li>
          ))}
        </ul>
      </aside>

      {/* Main Product Grid */}
      <div className="flex-1">
        <div className="mb-8 flex justify-between items-end border-b border-gray-200 pb-4">
          <div>
            <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">{selectedCategory}</h1>
            <p className="text-gray-500 mt-2">Showing {filteredProducts.length} premium products ready for purchase!</p>
          </div>
        </div>

        {filteredProducts.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-2xl shadow-sm border border-gray-100">
             <p className="text-gray-500 text-xl font-medium">No products found in this category.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredProducts.map(p => (
              <div key={p.id} className="bg-white rounded-2xl shadow-[0_4px_20px_rgb(0,0,0,0.06)] hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] transition-all duration-300 overflow-hidden border border-gray-100 flex flex-col group">
                <div className="relative overflow-hidden w-full h-48 bg-gray-100">
                  <img src={p.imageUrl || "https://picsum.photos/400/300"} alt={p.name} className="h-full w-full object-cover group-hover:scale-110 transition-transform duration-700 ease-in-out" />
                  <div className="absolute top-3 left-3 bg-white/90 backdrop-blur-sm text-primary text-xs font-bold px-3 py-1 rounded-full uppercase shadow-sm tracking-wider">
                    {p.categoryName || 'General'}
                  </div>
                </div>

                <div className="p-5 flex flex-col flex-grow">
                  <h3 className="text-lg font-bold text-gray-900 mb-1 leading-tight">{p.name}</h3>
                  <p className="text-gray-500 text-sm mb-4 line-clamp-2 leading-relaxed flex-grow">{p.description}</p>

                  <div className="flex items-center justify-between mb-4">
                    <span className="text-2xl font-extrabold text-gray-900">₹{p.price.toLocaleString("en-IN")}</span>
                  </div>

                  <div className="flex gap-2 mt-auto">
                    <button className="flex-1 bg-indigo-50 hover:bg-indigo-100 text-primary font-bold py-2 px-2 text-sm rounded-xl transition-colors duration-200">
                      Add to Cart
                    </button>
                    <button className="flex-1 bg-primary hover:bg-secondary text-white font-bold py-2 px-2 text-sm rounded-xl shadow-sm transition-all duration-200 hover:-translate-y-0.5">
                      Buy Now
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const Dashboard = () => {
  const role = localStorage.getItem('role');
  const [product, setProduct] = useState({ name: '', description: '', price: '', stock: '', categoryId: '', imageUrl: '' });
  const [message, setMessage] = useState('');

  const handleAddProduct = async (e) => {
    e.preventDefault();
    try {
      await api.post('/products', {
        name: product.name,
        description: product.description,
        price: parseFloat(product.price),
        stock: parseInt(product.stock),
        categoryId: product.categoryId ? parseInt(product.categoryId) : null,
        imageUrl: product.imageUrl
      });
      setMessage('Product listed successfully!');
      setProduct({ name: '', description: '', price: '', stock: '', categoryId: '', imageUrl: '' });
    } catch (err) {
      setMessage('Error listing product. Ensure you are an Admin.');
    }
  };

  return (
    <div className="py-12 px-8 max-w-7xl mx-auto">
      <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100 mb-8">
        <h1 className="text-4xl font-bold mb-4 text-gray-900">Dashboard</h1>
        <p className="text-lg text-gray-600">Welcome back to SmartPoint! Authentication functions are securely running here.</p>
      </div>

      {role === 'ADMIN' && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-indigo-100">
          <h2 className="text-2xl font-bold mb-4 text-indigo-700">Admin Area: List a New Product</h2>
          {message && <p className="mb-4 text-primary font-semibold">{message}</p>}
          <form onSubmit={handleAddProduct} className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <input type="text" placeholder="Product Name" required className="input-field" value={product.name} onChange={e => setProduct({...product, name: e.target.value})} />
            <input type="text" placeholder="Image URL (e.g. Unsplash URL)" className="input-field" value={product.imageUrl} onChange={e => setProduct({...product, imageUrl: e.target.value})} />
            <input type="number" step="0.01" placeholder="Price (₹)" required className="input-field" value={product.price} onChange={e => setProduct({...product, price: e.target.value})} />
            <input type="number" placeholder="Inventory Stock Qty" required className="input-field" value={product.stock} onChange={e => setProduct({...product, stock: e.target.value})} />
            <select className="input-field sm:col-span-2" value={product.categoryId} onChange={e => setProduct({...product, categoryId: e.target.value})}>
              <option value="">Select Category (Optional)</option>
              <option value="1">Tech</option>
              <option value="2">Fashion</option>
              <option value="3">Footwear</option>
              <option value="4">Appliances</option>
            </select>
            <textarea placeholder="Product Description" required className="input-field sm:col-span-2" rows="3" value={product.description} onChange={e => setProduct({...product, description: e.target.value})}></textarea>
            <button type="submit" className="btn-primary sm:col-span-2 py-3">List Product to Marketplace</button>
          </form>
        </div>
      )}
    </div>
  );
};

function App() {
  return (
    <Router>
      <div className="font-sans min-h-screen flex flex-col bg-slate-50">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/dashboard" element={<Dashboard />} />
          </Routes>
        </main>
        <footer className="bg-white border-t border-gray-200 py-8 mt-12">
            <p className="text-center text-gray-400 text-sm font-medium">© 2026 SmartPoint App. Premium Marketplace.</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
